const q = ($input.first() && $input.first().json && $input.first().json.query) || {};
const client = String(q.client || '').trim();
if (!client) throw new Error('client query param required (e.g. ?client=bayavoce)');
const sheetName = 'Calendar_' + client;
return [{ json: { client, sheetName } }];

const items = $input.all();
const posts = items.map(it => it.json || {}).filter(r => r && r.id);
posts.sort((a,b) => Number(a.order_index||0) - Number(b.order_index||0));
return [{ json: { ok: true, posts } }];
